function isValid(s: string): boolean {
  const stack: string[] = [];
  const pairs: Map<string, string> = new Map([
    [")", "("], ["]", "["], ["}", "{"]
  ]);
  for (const ch of s) {
    if (pairs.has(ch)) {
      if (stack.pop() !== pairs.get(ch)) return false;
    } else {
      stack.push(ch);
    }
  }
  return stack.length === 0;
}

console.log(isValid("()[]{}")); // true
console.log(isValid("(])"));    // false

